# The name of this view in Looker is "Order Details"
view: order_details {
  # The sql_table_name parameter indicates the underlying database table
  # to be used for all fields in this view.
  sql_table_name: "ANALYTICS"."ORDER_DETAILS" ;;

  # No primary key is defined for this view. In order to join this view in an Explore,
  # define primary_key: yes on a dimension that has no repeated values.

    # Here's what a typical dimension looks like in LookML.
    # A dimension is a groupable field that can be used to filter query results.
    # This dimension will be called "Billing Address Line1" in Explore.

  dimension: billing_address_line1 {
    type: string
    sql: ${TABLE}."BILLING_ADDRESS_LINE1" ;;
  }

  dimension: billing_address_line2 {
    type: string
    sql: ${TABLE}."BILLING_ADDRESS_LINE2" ;;
  }

  dimension: billing_country {
    type: string
    sql: ${TABLE}."BILLING_COUNTRY" ;;
  }

  dimension: billing_region {
    type: string
    sql: ${TABLE}."BILLING_REGION" ;;
  }

  dimension: billing_town_city {
    type: string
    sql: ${TABLE}."BILLING_TOWN_CITY" ;;
  }

  dimension: billing_zipcode {
    type: number
    sql: ${TABLE}."BILLING_ZIPCODE" ;;
  }

  dimension: category_id {
    type: number
    sql: ${TABLE}."CATEGORY_ID" ;;
  }

  dimension: category_name {
    type: string
    sql: ${TABLE}."CATEGORY_NAME" ;;
  }

  dimension: condition {
    type: string
    sql: ${TABLE}."CONDITION" ;;
  }

  dimension: cost_of_delivery {
    type: number
    sql: ${TABLE}."COST_OF_DELIVERY" ;;
  }

  dimension: cust_email {
    type: string
    sql: ${TABLE}."CUST_EMAIL" ;;
  }

  dimension: cust_first_name {
    type: string
    sql: ${TABLE}."CUST_FIRST_NAME" ;;
  }

  dimension: cust_last_name {
    type: string
    sql: ${TABLE}."CUST_LAST_NAME" ;;
  }

  dimension: customer_class {
    type: string
    sql: ${TABLE}."CUSTOMER_CLASS" ;;
  }

  dimension: customer_id {
    type: number
    sql: ${TABLE}."CUSTOMER_ID" ;;
  }

  dimension: delivery_status {
    type: string
    sql: ${TABLE}."DELIVERY_STATUS" ;;
  }

  dimension: delivery_type {
    type: string
    sql: ${TABLE}."DELIVERY_TYPE" ;;
  }

  dimension: discount_amount {
    type: number
    sql: ${TABLE}."DISCOUNT_AMOUNT" ;;
  }

  dimension: discount_percent {
    type: number
    sql: ${TABLE}."DISCOUNT_PERCENT" ;;
  }

  dimension: dispatch_date {
    type: string
    sql: ${TABLE}."DISPATCH_DATE" ;;
  }

  dimension: estimated_delivery {
    type: string
    sql: ${TABLE}."ESTIMATED_DELIVERY" ;;
  }

  dimension: gift_wrap {
    type: string
    sql: ${TABLE}."GIFT_WRAP" ;;
  }

  dimension: line_item_id {
    type: number
    sql: ${TABLE}."LINE_ITEM_ID" ;;
  }

  dimension: line_total {
    type: number
    sql: ${TABLE}."LINE_TOTAL" ;;
  }

  dimension: list_price {
    type: number
    sql: ${TABLE}."LIST_PRICE" ;;
  }

  dimension: order_date {
    type: string
    sql: ${TABLE}."ORDER_DATE" ;;
  }

  dimension: order_date_timestamp {
    type: date_time
    sql: TO_TIMESTAMP(${TABLE}."ORDER_DATE", 'YYYY-MM-DD HH24:MI:SS') ;;
  }

  dimension: order_id {
    type: number
    sql: ${TABLE}."ORDER_ID" ;;
  }

  dimension: order_mode {
    type: string
    sql: ${TABLE}."ORDER_MODE" ;;
  }

  dimension: order_status {
    type: number
    sql: ${TABLE}."ORDER_STATUS" ;;
  }

  dimension: order_total {
    type: number
    sql: ${TABLE}."ORDER_TOTAL" ;;
  }

  dimension: payment_method_code {
    type: string
    sql: ${TABLE}."PAYMENT_METHOD_CODE" ;;
  }

  dimension: phone_number {
    type: string
    sql: ${TABLE}."PHONE_NUMBER" ;;
  }

  dimension: product_description {
    type: string
    sql: ${TABLE}."PRODUCT_DESCRIPTION" ;;
  }

  dimension: product_id {
    type: number
    sql: ${TABLE}."PRODUCT_ID" ;;
  }

  dimension: product_name {
    type: string
    sql: ${TABLE}."PRODUCT_NAME" ;;
  }

  dimension: product_status {
    type: string
    sql: ${TABLE}."PRODUCT_STATUS" ;;
  }

  dimension: promotion_description {
    type: string
    sql: ${TABLE}."PROMOTION_DESCRIPTION" ;;
  }

  dimension: promotion_id {
    type: number
    sql: ${TABLE}."PROMOTION_ID" ;;
  }

  dimension: promotion_name {
    type: string
    sql: ${TABLE}."PROMOTION_NAME" ;;
  }

  dimension: quantity {
    type: number
    sql: ${TABLE}."QUANTITY" ;;
  }

  dimension: quantity_on_hand {
    type: number
    sql: ${TABLE}."QUANTITY_ON_HAND" ;;
  }

  dimension: return_date {
    type: string
    sql: ${TABLE}."RETURN_DATE" ;;
  }

  dimension: return_status {
    type: string
    sql: ${TABLE}."RETURN_STATUS" ;;
  }

  dimension: shipping_address_line1 {
    type: string
    sql: ${TABLE}."SHIPPING_ADDRESS_LINE1" ;;
  }

  dimension: shipping_address_line2 {
    type: string
    sql: ${TABLE}."SHIPPING_ADDRESS_LINE2" ;;
  }

  dimension: shipping_country {
    type: string
    sql: ${TABLE}."SHIPPING_COUNTRY" ;;
  }

  dimension: shipping_region {
    type: string
    sql: ${TABLE}."SHIPPING_REGION" ;;
  }

  dimension: shipping_town_city {
    type: string
    sql: ${TABLE}."SHIPPING_TOWN_CITY" ;;
  }

  dimension: shipping_zipcode {
    type: number
    sql: ${TABLE}."SHIPPING_ZIPCODE" ;;
  }

  dimension: stock_status {
    type: string
    sql: ${TABLE}."STOCK_STATUS" ;;
  }

  dimension: unit_price {
    type: number
    sql: ${TABLE}."UNIT_PRICE" ;;
  }
  # Dates and timestamps can be represented in Looker using a dimension group of type: time.
  # Looker converts dates and timestamps to the specified timeframes within the dimension group.

  dimension_group: updated {
    type: time
    timeframes: [raw, time, date, week, month, quarter, year]
    sql: ${TABLE}."UPDATED_AT" ;;
  }

  dimension: wait_till_complete_yn {
    type: string
    sql: ${TABLE}."WAIT_TILL_COMPLETE_YN" ;;
  }

  dimension: warehouse_id {
    type: number
    sql: ${TABLE}."WAREHOUSE_ID" ;;
  }

  dimension: warehouse_name {
    type: string
    sql: ${TABLE}."WAREHOUSE_NAME" ;;
  }
  measure: count {
    type: count
    drill_fields: [detail*]
  }

  # ----- Sets of fields for drilling ------
  set: detail {
    fields: [
  product_name,
  warehouse_name,
  category_name,
  cust_first_name,
  promotion_name,
  cust_last_name
  ]
  }

}

{{
    config(
        materialized='incremental',
        post_hook=[
            "DELETE FROM {{ this }} WHERE as_of_date < dateadd(day, -5, current_timestamp())"
        ]
    )
}}

select
  order_id
  , customer_id
  , order_status
  , order_total
  , updated_at::date as as_of_date

from
  {{ ref('order_details') }}

{% if is_incremental() %}

  -- this filter will only be applied on an incremental run
  where updated_at > (select max(as_of_date) from {{ this }})

{% endif %}
